function getGunAimDirection() {
    const rh = getRH(); if (!rh || rh.isNull()) return null;
    const hc = getHC();
    const refTf = (hc && !hc.isNull()) ? inv(hc, 'get_transform') : null;
    const refFwd = (refTf && !refTf.isNull()) ? inv(refTf, 'get_forward') : null;
    const refArr = refFwd ? [tryGet(refFwd,'x')||0, tryGet(refFwd,'y')||0, tryGet(refFwd,'z')||0] : [0, 0, 1];
    const candidates = ['forward', '-forward'];
    let best = 'forward', bestScore = -999999;
    for (const c of candidates) {
        try {
            let vec;
            if (c === 'forward') vec = inv(rh, 'get_forward');
            else vec = v3Mul(-1, inv(rh, 'get_forward'));
            if (!vec) continue;
            const v = [tryGet(vec,'x')||0, tryGet(vec,'y')||0, tryGet(vec,'z')||0];
            const score = v[0]*refArr[0] + v[1]*refArr[1] + v[2]*refArr[2];
            if (score > bestScore) { bestScore = score; best = c; }
        } catch(_) {}
    }
    let result;
    try {
        if (best === '-forward') result = v3Mul(-1, inv(rh, 'get_forward'));
        else result = inv(rh, 'get_forward');
    } catch(_) { return inv(rh, 'get_forward'); }
    if (!result) return inv(rh, 'get_forward');
    const mx = tryGet(result,'x')||0, my = tryGet(result,'y')||0, mz = tryGet(result,'z')||0;
    const mag = Math.sqrt(mx*mx + my*my + mz*mz) || 1;
    return v3(mx/mag, my/mag, mz/mag);
}

