        const forward = headTf ? inv(headTf, 'get_forward') : null;
        let spawnPos = forward ? v3Add(pos, v3Mul(1.5, forward)) : pos;
        if ((total || 0) > 1) {
            const angle = ((index || 0) / total) * Math.PI * 2;
            spawnPos = v3Add(pos, v3(Math.cos(angle) * 2, 0, Math.sin(angle) * 2));
        }
        let obj = spawnNetPrefab('NetPlayer', spawnPos, rot, false);
        if (!obj || obj.isNull()) obj = spawnNetPrefab('NetworkedPlayer', spawnPos, rot, false);
        if (!obj || obj.isNull()) return null;
        let np = null;
        try { np = obj.method('GetComponent', 1).inflate(NetPlayer).invoke(); } catch(_) {}
        if (!np || np.isNull()) {
            const objGo = go(obj);
            try { if (objGo && !objGo.isNull()) np = objGo.method('GetComponent', 1).inflate(NetPlayer).invoke(); } catch(_) {}
        }
        const tf = np && !np.isNull() ? gt(np) : gt(obj);
